const React = require('react');
const { render, fireEvent, screen, waitFor } = require('@testing-library/react');
const proxyquire = require('proxyquire').noCallThru();

// Mock the CSS import – return an empty object
const AuthModal = proxyquire('../../src/components/AuthModal.jsx', {
  './AuthModal.css': {}
}).default; // if your component uses export default

console.log('AuthModal type:', typeof AuthModal); // should be 'function'

describe('AuthModal', () => {
  const mockOnClose = jasmine.createSpy('onClose');
  const mockOnLoginSuccess = jasmine.createSpy('onLoginSuccess');

  beforeEach(() => {
    mockOnClose.calls.reset();
    mockOnLoginSuccess.calls.reset();
  });

  it('does not render when isOpen is false', () => {
    render(<AuthModal isOpen={false} onClose={mockOnClose} />);
    expect(screen.queryByText(/Welcome to Meka/i)).toBeNull();
  });

  it('renders when isOpen is true', () => {
    render(<AuthModal isOpen={true} onClose={mockOnClose} />);
    expect(screen.getByText(/Welcome to Meka/i)).toBeTruthy();
    expect(screen.getByPlaceholderText('Username')).toBeTruthy();
    expect(screen.getByPlaceholderText('Password')).toBeTruthy();
    expect(screen.getByText('Log In')).toBeTruthy();
    expect(screen.getByText('Create Account')).toBeTruthy();
  });

  it('calls onClose when close button is clicked', () => {
    render(<AuthModal isOpen={true} onClose={mockOnClose} />);
    fireEvent.click(screen.getByText('✕'));
    expect(mockOnClose).toHaveBeenCalled();
  });

  describe('Login flow', () => {
    beforeEach(() => {
      spyOn(window, 'fetch').and.returnValue(
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve({ username: 'testuser' })
        })
      );
    });

    it('calls fetch with correct parameters on login', async () => {
      render(
        <AuthModal
          isOpen={true}
          onClose={mockOnClose}
          onLoginSuccess={mockOnLoginSuccess}
        />
      );

      fireEvent.change(screen.getByPlaceholderText('Username'), {
        target: { value: 'testuser' }
      });
      fireEvent.change(screen.getByPlaceholderText('Password'), {
        target: { value: 'secret' }
      });
      fireEvent.click(screen.getByText('Log In'));

      await waitFor(() => {
        expect(window.fetch).toHaveBeenCalledWith(
          'http://localhost:3001/api/login',
          jasmine.objectContaining({
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ username: 'testuser', password: 'secret' })
          })
        );
      });

      await waitFor(() => {
        expect(mockOnLoginSuccess).toHaveBeenCalledWith({ username: 'testuser' });
        expect(mockOnClose).toHaveBeenCalled();
      });
    });

    it('displays error message on login failure', async () => {
      window.fetch.and.returnValue(
        Promise.resolve({
          ok: false,
          json: () => Promise.resolve({ error: 'Invalid credentials' })
        })
      );

      render(
        <AuthModal
          isOpen={true}
          onClose={mockOnClose}
          onLoginSuccess={mockOnLoginSuccess}
        />
      );

      fireEvent.change(screen.getByPlaceholderText('Username'), {
        target: { value: 'bad' }
      });
      fireEvent.change(screen.getByPlaceholderText('Password'), {
        target: { value: 'wrong' }
      });
      fireEvent.click(screen.getByText('Log In'));

      await waitFor(() => {
        expect(screen.getByText(/Invalid credentials/i)).toBeTruthy();
      });
      expect(mockOnLoginSuccess).not.toHaveBeenCalled();
      expect(mockOnClose).not.toHaveBeenCalled();
    });
  });

  describe('Registration flow', () => {
    beforeEach(() => {
      spyOn(window, 'fetch').and.returnValue(
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve({ username: 'newuser' })
        })
      );
      spyOn(window, 'alert').and.stub();
    });

    it('calls fetch with correct parameters on register', async () => {
      render(
        <AuthModal
          isOpen={true}
          onClose={mockOnClose}
          onLoginSuccess={mockOnLoginSuccess}
        />
      );

      fireEvent.change(screen.getByPlaceholderText('Username'), {
        target: { value: 'newuser' }
      });
      fireEvent.change(screen.getByPlaceholderText('Password'), {
        target: { value: 'secret' }
      });
      fireEvent.click(screen.getByText('Create Account'));

      await waitFor(() => {
        expect(window.fetch).toHaveBeenCalledWith(
          'http://localhost:3001/api/register',
          jasmine.objectContaining({
            method: 'POST',
            body: JSON.stringify({ username: 'newuser', password: 'secret' })
          })
        );
      });

      await waitFor(() => {
        expect(window.alert).toHaveBeenCalledWith('Account created! Please log in.');
      });

      expect(mockOnLoginSuccess).not.toHaveBeenCalled();
      expect(mockOnClose).not.toHaveBeenCalled();
    });

    it('displays error message on registration failure', async () => {
      window.fetch.and.returnValue(
        Promise.resolve({
          ok: false,
          json: () => Promise.resolve({ error: 'Username already exists' })
        })
      );

      render(<AuthModal isOpen={true} onClose={mockOnClose} />);

      fireEvent.change(screen.getByPlaceholderText('Username'), {
        target: { value: 'existing' }
      });
      fireEvent.change(screen.getByPlaceholderText('Password'), {
        target: { value: 'secret' }
      });
      fireEvent.click(screen.getByText('Create Account'));

      await waitFor(() => {
        expect(screen.getByText(/Username already exists/i)).toBeTruthy();
      });
    });
  });
});

